/// <summary>
/// Extension class of <c>CustPrintOutInvoice</c> for text block management
/// </summary>
[ExtensionOf(classStr(CustPrintOutInvoice))]
final class FWFTextBlockCustPrintOutInvoice_Extension
{
}

Method.Source:
void createProforma()
{
    CustInvoiceTrans custInvoiceTransLocal;
    ;
    next createProforma();

    while select custInvoiceTransLocal
        where custInvoiceTransLocal.SalesId == this.custInvoiceJour.SalesId
            && custInvoiceTransLocal.InvoiceId == this.custInvoiceJour.InvoiceId
            && custInvoiceTransLocal.InvoiceDate == this.custInvoiceJour.InvoiceDate
            && custInvoiceTransLocal.numberSequenceGroup == this.custInvoiceJour.numberSequenceGroup
    {
        FWFTextBlockEventHandler::newParameters(custInvoiceTransLocal, EventLogType::Insert).run();
    }

    FWFTextBlockEventHandler::newParameters(this.custInvoiceJour, EventLogType::Insert).run();
}
